(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[1061],{4104:(e,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>n});const n={key:"v-3118d8bf",path:"/sql/view/join/outer/Left/",title:"Outer - Left Join",lang:"en-US",frontmatter:{},excerpt:"",headers:[],filePathRelative:"sql/view/join/outer/Left/README.md",git:{updatedTime:162676698e4,contributors:[]}}},5413:(e,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>t});const n=(0,a(6252).uE)('<h1 id="outer-left-join" tabindex="-1"><a class="header-anchor" href="#outer-left-join" aria-hidden="true">#</a> Outer - Left Join</h1><p><img src="https://static1.squarespace.com/static/5732253c8a65e244fd589e4c/t/5744bdad40261de572cbbc49/1464122809233/?format=300w" alt="Select all from Table A, along with records from Table B for which the join condition is met (if at all)."></p><p>ตัวตารางฝั่งซ้าย (order) จะมีค่า NULL value</p><div class="language-sql ext-sql line-numbers-mode"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span>\n<span class="token keyword">FROM</span> <span class="token keyword">order</span>\n<span class="token keyword">LEFT</span> <span class="token keyword">OUTER</span> <span class="token keyword">JOIN</span> product\n<span class="token keyword">USING</span> <span class="token punctuation">(</span>P_Code<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>มีข้อมูล order ครบ บรรทัดที่ product ไม่มีข้อมูลก็จะเขียน NULL</p><p>หมายความว่า ตาราง จะมีข้อมูล ORDER (ตารางฝั่งซ้าย) ทั้งหมดทุก ROW แต่จะมีข้อมูลฝั่งขวาที่จะมี NULL ได้</p>',6),t={render:function(e,s){return n}}}}]);